      print({
        success: result.success,
        filePath: result.filePath,
        rawBytes: result.rawCode?.length || 0,
        transpiledBytes: result.transpiledCode?.length || 0
      });
      break;
    }
    default:
      usage();
      process.exit(command ? 1 : 0);
  }
} catch (err) {
  console.error(err.message);
  process.exit(1);
