  const drawScope = () => {
    analyser.getByteTimeDomainData(timeData);
    analyser.getByteFrequencyData(freqData);
    pulse *= 0.9;
    visualPhase += 0.014 + pulse * 0.045;

    let subEnergy = 0;
    for (let i = 0; i < 10; i += 1) subEnergy += freqData[i] / 255;
    subEnergy /= 10;

    const w = canvas.width;
    const h = canvas.height;
    canvasCtx.clearRect(0, 0, w, h);
    const bg = canvasCtx.createLinearGradient(0, 0, w, h);
    bg.addColorStop(0, `hsl(184, 70%, ${5 + subEnergy * 9}%)`);
    bg.addColorStop(0.55, `hsl(25, 78%, ${7 + pulse * 10}%)`);
    bg.addColorStop(1, `hsl(132, 56%, ${5 + subEnergy * 8}%)`);
    canvasCtx.fillStyle = bg;
    canvasCtx.fillRect(0, 0, w, h);

    canvasCtx.globalAlpha = 0.22;
    canvasCtx.strokeStyle = '#64748b';
    canvasCtx.lineWidth = 1;
    for (let x = 0; x < w; x += 28) {
      canvasCtx.beginPath();
      canvasCtx.moveTo(x, 0);
      canvasCtx.lineTo(x - 18, h);
      canvasCtx.stroke();
    }
    canvasCtx.globalAlpha = 1;

    canvasCtx.globalCompositeOperation = 'lighter';
    for (let i = 0; i < 18; i += 1) {
      const magnitude = freqData[i] / 255;
      const barW = w / 22;
      const x = 8 + i * (barW + 2);
      const barH = magnitude * h * 0.8;
      canvasCtx.fillStyle = `hsla(${24 + i * 7}, 92%, ${50 + magnitude * 22}%, ${0.18 + magnitude * 0.56})`;
      canvasCtx.fillRect(x, h - barH, barW, barH);
    }

    canvasCtx.strokeStyle = `rgba(45, 212, 191, ${0.5 + subEnergy * 0.4})`;
    canvasCtx.lineWidth = 1.5 + subEnergy * 2.4;
    canvasCtx.beginPath();
    for (let i = 0; i < timeData.length; i += 1) {
      const x = i / (timeData.length - 1) * w;
      const y = h * 0.5 + (timeData[i] / 255 - 0.5) * h * (0.84 + pulse * 0.36);
      if (i === 0) canvasCtx.moveTo(x, y);
      else canvasCtx.lineTo(x, y);
    }
    canvasCtx.stroke();
    canvasCtx.globalCompositeOperation = 'source-over';

    const dotX = (currentStep % 16) / 15 * (w - 18) + 9;
    canvasCtx.fillStyle = state.enabled ? '#fb923c' : '#64748b';
    canvasCtx.beginPath();
    canvasCtx.arc(dotX, 9 + Math.sin(visualPhase) * 2, 3.4 + pulse * 2.8, 0, Math.PI * 2);
    canvasCtx.fill();
  };

  updateAudio();
  render();

  return {
    update() {
      drawScope();
    },
    getState() {
      return {
        stateVersion: STATE_VERSION,
        enabled: state.enabled,
        rootMidi: state.rootMidi,
        sequence: [...state.sequence],
        gain: state.gain,
        decay: state.decay,
        tone: state.tone,
        drive: state.drive,
        punch: state.punch,
        slide: state.slide,
        variation: state.variation
      };
    },
    destroy() {
      unsubscribeClock();
      unsubscribeRemote();
      timers.forEach((timer) => clearTimeout(timer));
      timers.clear();
      activeNodes.forEach((node) => {
        try { if (typeof node.stop === 'function') node.stop(); } catch (error) {}
        try { node.disconnect(); } catch (error) {}
      });
      activeNodes.clear();
      [output, dcBlock, shaper, lowpass, compressor, analyser].forEach((node) => {
        try { node.disconnect(); } catch (error) {}
      });
    }
  };
}

const STATE_VERSION = 'hiphop-808-bass-v1';

const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
const midiToFreq = (midi) => 440 * Math.pow(2, (midi - 69) / 12);

export default function setup(ctx, prevState) {
  const elementId = ctx.elementId || 'elem_hiphop_808_bass';
  const busKey = `hiphop-808:${elementId}:state`;
  const matchesVersion = prevState?.stateVersion === STATE_VERSION;
  const defaultSequence = [0, null, 0, null, 7, null, 5, null, 0, null, 10, null, 7, 5, null, 12];
  const scaleChoices = [null, 0, 3, 5, 7, 10, 12, 15, 17, 19];
  const roots = [
    ['C', 36],
    ['C#', 37],
    ['D', 38],
    ['Eb', 39],
    ['E', 40],
    ['F', 41],
    ['F#', 42],
    ['G', 43],
    ['Ab', 44],
    ['A', 45],
    ['Bb', 46],
    ['B', 47]
  ];

  const cloneSequence = (sequence) => {
    const source = Array.isArray(sequence) ? sequence : defaultSequence;
    return Array.from({ length: 16 }, (_, index) => {
      const value = source[index];
      return Number.isFinite(value) ? clamp(Math.round(value), 0, 24) : null;
    });
  };

  const state = {
    stateVersion: STATE_VERSION,
    enabled: typeof prevState?.enabled === 'boolean' ? prevState.enabled : true,
    rootMidi: matchesVersion && Number.isFinite(prevState?.rootMidi) ? clamp(Math.round(prevState.rootMidi), 36, 47) : 41,
    sequence: cloneSequence(matchesVersion ? prevState?.sequence : defaultSequence),
    gain: matchesVersion && Number.isFinite(prevState?.gain) ? clamp(prevState.gain, 0, 1) : 0.72,
    decay: matchesVersion && Number.isFinite(prevState?.decay) ? clamp(prevState.decay, 0, 1) : 0.62,
    tone: matchesVersion && Number.isFinite(prevState?.tone) ? clamp(prevState.tone, 0, 1) : 0.42,
    drive: matchesVersion && Number.isFinite(prevState?.drive) ? clamp(prevState.drive, 0, 1) : 0.34,
    punch: matchesVersion && Number.isFinite(prevState?.punch) ? clamp(prevState.punch, 0, 1) : 0.52,
    slide: matchesVersion && Number.isFinite(prevState?.slide) ? clamp(prevState.slide, 0, 1) : 0.44,
    variation: matchesVersion && Number.isFinite(prevState?.variation) ? clamp(prevState.variation, 0, 1) : 0.28
  };

  const audio = ctx.audioCtx;
  const now = () => audio.currentTime;
  const names = ['C', 'C#', 'D', 'Eb', 'E', 'F', 'F#', 'G', 'Ab', 'A', 'Bb', 'B'];
  const noteName = (offset) => Number.isFinite(offset) ? names[(state.rootMidi + offset + 1200) % 12] : '--';

  const output = audio.createGain();
  const dcBlock = audio.createBiquadFilter();
  const shaper = audio.createWaveShaper();
  const lowpass = audio.createBiquadFilter();
  const compressor = audio.createDynamicsCompressor();
  const analyser = audio.createAnalyser();

  output.gain.setValueAtTime(state.enabled ? state.gain : 0, now());
  dcBlock.type = 'highpass';
  dcBlock.frequency.setValueAtTime(24, now());
  lowpass.type = 'lowpass';
  lowpass.frequency.setValueAtTime(820, now());
  lowpass.Q.setValueAtTime(1.2, now());
  compressor.threshold.setValueAtTime(-20, now());
  compressor.knee.setValueAtTime(18, now());
  compressor.ratio.setValueAtTime(5, now());
  compressor.attack.setValueAtTime(0.006, now());
  compressor.release.setValueAtTime(0.18, now());
  analyser.fftSize = 256;

  output.connect(dcBlock);
  dcBlock.connect(shaper);
  shaper.connect(lowpass);
  lowpass.connect(compressor);
  compressor.connect(analyser);
  analyser.connect(ctx.audioOut);

  const makeDriveCurve = (amount) => {
    const samples = 2048;
    const curve = new Float32Array(samples);
    const k = 1.5 + amount * 42;
    for (let i = 0; i < samples; i += 1) {
      const x = i * 2 / samples - 1;
      curve[i] = Math.tanh(k * x) / Math.tanh(k);
    }
    return curve;
  };

  const activeNodes = new Set();
  const timers = new Set();
  let currentStep = -1;
  let lastFreq = midiToFreq(state.rootMidi);
  let pulse = 0;
  let visualPhase = 0;
  let applyingRemote = false;

  const setParam = (param, value, time = now(), smoothing = 0.025) => {
    param.cancelScheduledValues(time);
    param.setTargetAtTime(value, value > 0 ? time : time + 0.001, smoothing);
  };

  const updateAudio = () => {
    const t = now();
    setParam(output.gain, state.enabled ? state.gain : 0, t, 0.018);
    shaper.curve = makeDriveCurve(state.drive);
    shaper.oversample = state.drive > 0.45 ? '4x' : '2x';
    lowpass.frequency.setTargetAtTime(150 + state.tone * 1350, t, 0.04);
    lowpass.Q.setTargetAtTime(0.8 + state.punch * 3.4, t, 0.04);
    compressor.threshold.setTargetAtTime(-24 + state.drive * 8, t, 0.05);
  };

  const remember = (...nodes) => nodes.forEach((node) => activeNodes.add(node));

  const cleanupLater = (time, ...nodes) => {
    const timer = setTimeout(() => {
      timers.delete(timer);
      nodes.forEach((node) => {
        try { node.disconnect(); } catch (error) {}
        activeNodes.delete(node);
      });
    }, Math.max(100, (time - now()) * 1000 + 140));
    timers.add(timer);
  };

  const triggerBass = (midi, velocity, time, duration, step) => {
    if (!state.enabled) return;
    const t = Math.max(time, now() + 0.003);
    const freq = midiToFreq(midi);
    const noteLength = duration * (1.3 + state.decay * 5.4);
    const stopAt = t + noteLength + 0.22;
    const slideTime = state.slide * 0.17;
    const dropRatio = 1.7 + state.punch * 2.2;

    const sub = audio.createOscillator();
    const body = audio.createOscillator();
    const transient = audio.createOscillator();
    const subGain = audio.createGain();
    const bodyGain = audio.createGain();
    const transientGain = audio.createGain();
    const voiceGain = audio.createGain();
    const bodyFilter = audio.createBiquadFilter();

    sub.type = 'sine';
    body.type = state.drive > 0.55 ? 'sawtooth' : 'triangle';
    transient.type = 'sine';
    bodyFilter.type = 'lowpass';
    bodyFilter.frequency.setValueAtTime(95 + state.tone * 360, t);
    bodyFilter.Q.setValueAtTime(1.2 + state.punch * 2.4, t);

    const startFreq = state.slide > 0.02 ? lastFreq : freq;
    sub.frequency.setValueAtTime(startFreq, t);
    body.frequency.setValueAtTime(startFreq * 1.003, t);
    if (slideTime > 0.004 && Math.abs(Math.log2(freq / Math.max(1, startFreq))) < 1.5) {
      sub.frequency.exponentialRampToValueAtTime(freq, t + slideTime);
      body.frequency.exponentialRampToValueAtTime(freq * 1.003, t + slideTime);
    } else {
      sub.frequency.setValueAtTime(freq, t);
      body.frequency.setValueAtTime(freq * 1.003, t);
    }

    transient.frequency.setValueAtTime(freq * dropRatio, t);
    transient.frequency.exponentialRampToValueAtTime(freq * 1.05, t + 0.045 + state.punch * 0.035);

    subGain.gain.setValueAtTime(0.0001, t);
    subGain.gain.exponentialRampToValueAtTime(0.72 * velocity, t + 0.018);
    subGain.gain.setTargetAtTime(0.0001, t + noteLength, 0.11 + state.decay * 0.18);

    bodyGain.gain.setValueAtTime(0.0001, t);
    bodyGain.gain.exponentialRampToValueAtTime((0.22 + state.drive * 0.22) * velocity, t + 0.012);
    bodyGain.gain.setTargetAtTime(0.0001, t + noteLength * 0.78, 0.08 + state.decay * 0.12);

    transientGain.gain.setValueAtTime(0.0001, t);
    transientGain.gain.exponentialRampToValueAtTime((0.13 + state.punch * 0.28) * velocity, t + 0.006);
    transientGain.gain.exponentialRampToValueAtTime(0.0001, t + 0.05 + state.punch * 0.05);

    voiceGain.gain.setValueAtTime(0.62, t);
    sub.connect(subGain);
    body.connect(bodyFilter);
    bodyFilter.connect(bodyGain);
    transient.connect(transientGain);
    subGain.connect(voiceGain);
    bodyGain.connect(voiceGain);
    transientGain.connect(voiceGain);
    voiceGain.connect(output);

    sub.start(t);
    body.start(t);
    transient.start(t);
    sub.stop(stopAt);
    body.stop(stopAt);
    transient.stop(t + 0.14);

    lastFreq = freq;
    pulse = Math.max(pulse, velocity);
    remember(sub, body, transient, subGain, bodyGain, transientGain, bodyFilter, voiceGain);
    cleanupLater(stopAt, sub, body, transient, subGain, bodyGain, transientGain, bodyFilter, voiceGain);

    if (state.variation > 0.55 && step % 16 === 14) {
      triggerGhost(midi + 12, velocity * 0.38, t + duration * 0.52, duration * 0.42);
    }
  };

  const triggerGhost = (midi, velocity, time, duration) => {
    const t = Math.max(time, now() + 0.003);
    const freq = midiToFreq(midi);
    const osc = audio.createOscillator();
    const gain = audio.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(freq, t);
    gain.gain.setValueAtTime(0.0001, t);
    gain.gain.exponentialRampToValueAtTime(0.19 * velocity, t + 0.01);
    gain.gain.exponentialRampToValueAtTime(0.0001, t + duration);
    osc.connect(gain);
    gain.connect(output);
    osc.start(t);
    osc.stop(t + duration + 0.08);
    remember(osc, gain);
    cleanupLater(t + duration + 0.08, osc, gain);
  };

  ctx.domRoot.innerHTML = `
    <style>
      :host { display: block; height: 100%; }
      .bass {
        box-sizing: border-box;
        width: 100%;
        height: 100%;
        min-width: 280px;
        min-height: 220px;
        display: grid;
        grid-template-rows: auto 58px auto auto;
        gap: 8px;
        padding: 10px;
        overflow: hidden;
        color: #f8fafc;
        background:
          linear-gradient(135deg, rgba(5, 8, 12, 0.98), rgba(13, 18, 20, 0.98) 56%, rgba(23, 18, 9, 0.98)),
          repeating-linear-gradient(0deg, rgba(20, 184, 166, 0.055) 0 1px, transparent 1px 20px);
        border: 1px solid rgba(251, 146, 60, 0.62);
        border-radius: 8px;
        font: 10px/1.2 ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
        box-shadow: inset 0 0 24px rgba(251, 146, 60, 0.08);
      }
      .top {
        min-width: 0;
        display: grid;
        grid-template-columns: 1fr auto auto;
        align-items: center;
        gap: 7px;
      }
      h2 {
        margin: 0;
        color: #fb923c;
        font-size: 14px;
        line-height: 1;
        letter-spacing: 0;
      }
      .tag {
        margin-top: 2px;
        color: #94a3b8;
        font-size: 9px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
      }
      button,
      input,
      select { font: inherit; }
      .toggle {
        width: 48px;
        height: 28px;
        padding: 0;
        border: 1px solid rgba(251, 146, 60, 0.72);
        border-radius: 5px;
        color: #111827;
        background: #fb923c;
        cursor: pointer;
      }
      .toggle.off {
        color: #cbd5e1;
        background: rgba(15, 23, 42, 0.82);
      }
      select {
        height: 28px;
        color: #ecfeff;
        background: rgba(2, 6, 23, 0.78);
        border: 1px solid rgba(148, 163, 184, 0.34);
        border-radius: 5px;
        outline: none;
      }
      .scope {
        min-width: 0;
        border: 1px solid rgba(148, 163, 184, 0.28);
        border-radius: 6px;
        background: #040609;
        overflow: hidden;
      }
      canvas {
        display: block;
        width: 100%;
        height: 100%;
      }
      .controls {
        display: grid;
        grid-template-columns: repeat(3, minmax(0, 1fr));
        gap: 5px 8px;
      }
      label {
        min-width: 0;
        display: grid;
        grid-template-columns: auto minmax(0, 1fr);
        align-items: center;
        gap: 5px;
        color: #cbd5e1;
      }
      input[type="range"] {
        width: 100%;
        min-width: 0;
        height: 14px;
        accent-color: #fb923c;
      }
      .steps {
        display: grid;
        grid-template-columns: repeat(8, minmax(0, 1fr));
        gap: 3px;
      }
      .step {
        height: 20px;
        min-width: 0;
        padding: 0;
        color: #fed7aa;
        background: rgba(31, 41, 55, 0.94);
        border: 1px solid rgba(148, 163, 184, 0.24);
        border-radius: 4px;
        cursor: pointer;
        overflow: hidden;
      }
      .step.on {
        color: #111827;
        background: #fb923c;
        border-color: rgba(253, 186, 116, 0.82);
      }
      .step.current {
        color: #042f2e;
        background: #2dd4bf;
        border-color: #99f6e4;
        box-shadow: 0 0 12px rgba(45, 212, 191, 0.68);
      }
    </style>
    <div class="bass">
      <div class="top">
        <div>
          <h2>808 Bass</h2>
          <div class="tag">sub drop / slide / punch</div>
        </div>
        <select id="root" title="root note"></select>
        <button class="toggle" id="enabled" type="button"></button>
      </div>
      <div class="scope"><canvas id="scope" width="320" height="58"></canvas></div>
      <div class="controls">
        <label>gain <input id="gain" type="range" min="0" max="1" step="0.01"></label>
        <label>decay <input id="decay" type="range" min="0" max="1" step="0.01"></label>
        <label>tone <input id="tone" type="range" min="0" max="1" step="0.01"></label>
        <label>drive <input id="drive" type="range" min="0" max="1" step="0.01"></label>
        <label>punch <input id="punch" type="range" min="0" max="1" step="0.01"></label>
        <label>slide <input id="slide" type="range" min="0" max="1" step="0.01"></label>
      </div>
      <div class="steps" id="steps"></div>
    </div>
  `;

  const rootSelect = ctx.domRoot.querySelector('#root');
  const enabledButton = ctx.domRoot.querySelector('#enabled');
  const stepsEl = ctx.domRoot.querySelector('#steps');
  const canvas = ctx.domRoot.querySelector('#scope');
  const canvasCtx = canvas.getContext('2d');
  const inputs = {
    gain: ctx.domRoot.querySelector('#gain'),
    decay: ctx.domRoot.querySelector('#decay'),
    tone: ctx.domRoot.querySelector('#tone'),
    drive: ctx.domRoot.querySelector('#drive'),
    punch: ctx.domRoot.querySelector('#punch'),
    slide: ctx.domRoot.querySelector('#slide')
  };

  rootSelect.innerHTML = roots.map(([name, midi]) => `<option value="${midi}">${name}</option>`).join('');

  const stepButtons = state.sequence.map((_, index) => {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'step';
    button.dataset.index = String(index);
    stepsEl.appendChild(button);
    return button;
  });

  const render = () => {
    enabledButton.textContent = state.enabled ? 'on' : 'mute';
    enabledButton.classList.toggle('off', !state.enabled);
    rootSelect.value = String(state.rootMidi);
    Object.entries(inputs).forEach(([key, input]) => {
      input.value = String(state[key]);
    });
    stepButtons.forEach((button, index) => {
      const note = state.sequence[index];
      button.textContent = noteName(note);
      button.classList.toggle('on', note !== null);
      button.classList.toggle('current', index === currentStep);
    });
  };

  const publishState = () => {
    if (applyingRemote) return;
    ctx.bus.pubGlobal(busKey, {
      enabled: state.enabled,
      rootMidi: state.rootMidi,
      sequence: state.sequence,
      gain: state.gain,
      decay: state.decay,
      tone: state.tone,
      drive: state.drive,
      punch: state.punch,
      slide: state.slide,
      variation: state.variation
    });
  };

  enabledButton.addEventListener('click', () => {
    state.enabled = !state.enabled;
    updateAudio();
    render();
    publishState();
  });

  rootSelect.addEventListener('change', () => {
    state.rootMidi = Number(rootSelect.value);
    lastFreq = midiToFreq(state.rootMidi);
    render();
    publishState();
  });

  Object.entries(inputs).forEach(([key, input]) => {
    input.addEventListener('input', () => {
      state[key] = clamp(Number(input.value), 0, 1);
      updateAudio();
      publishState();
    });
  });

  stepButtons.forEach((button, index) => {
    button.addEventListener('click', () => {
      const currentChoice = scaleChoices.findIndex((choice) => choice === state.sequence[index]);
      state.sequence[index] = scaleChoices[(currentChoice + 1) % scaleChoices.length];
      render();
      publishState();
    });
  });

  const unsubscribeRemote = ctx.bus.subGlobal(busKey, (value) => {
    if (!value || typeof value !== 'object') return;
    applyingRemote = true;
    if (typeof value.enabled === 'boolean') state.enabled = value.enabled;
    if (Number.isFinite(value.rootMidi)) state.rootMidi = clamp(Math.round(value.rootMidi), 36, 47);
    if (Array.isArray(value.sequence)) state.sequence = cloneSequence(value.sequence);
    ['gain', 'decay', 'tone', 'drive', 'punch', 'slide', 'variation'].forEach((key) => {
      if (Number.isFinite(value[key])) state[key] = clamp(Number(value[key]), 0, 1);
    });
    updateAudio();
    render();
    applyingRemote = false;
  });

  const unsubscribeClock = ctx.clock.onTick(({ step, time, duration }) => {
    currentStep = step % 16;
    render();
    if (!state.enabled) return;
    const offset = state.sequence[currentStep];
    if (offset === null) return;
    const accent = currentStep === 0 || currentStep === 8 ? 1 : currentStep % 4 === 0 ? 0.86 : 0.7;
    const late = currentStep % 2 === 1 ? duration * 0.045 : 0;
    const octaveDrop = currentStep === 8 && state.variation > 0.2 ? -12 : 0;
    triggerBass(state.rootMidi + offset + octaveDrop, accent, time + late, duration, step);
  });

  const timeData = new Uint8Array(analyser.frequencyBinCount);
  const freqData = new Uint8Array(analyser.frequencyBinCount);

  const drawScope = () => {
    analyser.getByteTimeDomainData(timeData);
    analyser.getByteFrequencyData(freqData);
    pulse *= 0.9;
    visualPhase += 0.014 + pulse * 0.045;

    let subEnergy = 0;
    for (let i = 0; i < 10; i += 1) subEnergy += freqData[i] / 255;
    subEnergy /= 10;

    const w = canvas.width;
    const h = canvas.height;
    canvasCtx.clearRect(0, 0, w, h);
    const bg = canvasCtx.createLinearGradient(0, 0, w, h);
    bg.addColorStop(0, `hsl(184, 70%, ${5 + subEnergy * 9}%)`);
    bg.addColorStop(0.55, `hsl(25, 78%, ${7 + pulse * 10}%)`);
    bg.addColorStop(1, `hsl(132, 56%, ${5 + subEnergy * 8}%)`);
    canvasCtx.fillStyle = bg;
    canvasCtx.fillRect(0, 0, w, h);

    canvasCtx.globalAlpha = 0.22;
    canvasCtx.strokeStyle = '#64748b';
    canvasCtx.lineWidth = 1;
    for (let x = 0; x < w; x += 28) {
      canvasCtx.beginPath();
      canvasCtx.moveTo(x, 0);
      canvasCtx.lineTo(x - 18, h);
      canvasCtx.stroke();
    }
    canvasCtx.globalAlpha = 1;

    canvasCtx.globalCompositeOperation = 'lighter';
    for (let i = 0; i < 18; i += 1) {
      const magnitude = freqData[i] / 255;
      const barW = w / 22;
      const x = 8 + i * (barW + 2);
      const barH = magnitude * h * 0.8;
      canvasCtx.fillStyle = `hsla(${24 + i * 7}, 92%, ${50 + magnitude * 22}%, ${0.18 + magnitude * 0.56})`;
      canvasCtx.fillRect(x, h - barH, barW, barH);
    }

