  const matchesVersion = prevState?.stateVersion === STATE_VERSION;
  const keys = [
    ['C', 60], ['Db', 61], ['D', 62], ['Eb', 63], ['E', 64], ['F', 65],
    ['Gb', 66], ['G', 67], ['Ab', 68], ['A', 69], ['Bb', 70], ['B', 71]
  ];

  const state = {
    stateVersion: STATE_VERSION,
    enabled: typeof prevState?.enabled === 'boolean' ? prevState.enabled : true,
    keyMidi: matchesVersion && Number.isFinite(prevState?.keyMidi) ? clamp(Math.round(prevState.keyMidi), 60, 71) : 64,
    gain: matchesVersion && Number.isFinite(prevState?.gain) ? clamp(prevState.gain, 0, 1) : 0.56,
    body: matchesVersion && Number.isFinite(prevState?.body) ? clamp(prevState.body, 0, 1) : 0.58,
    bright: matchesVersion && Number.isFinite(prevState?.bright) ? clamp(prevState.bright, 0, 1) : 0.48,
    room: matchesVersion && Number.isFinite(prevState?.room) ? clamp(prevState.room, 0, 1) : 0.5,
    motion: matchesVersion && Number.isFinite(prevState?.motion) ? clamp(prevState.motion, 0, 1) : 0.52,
