  bodyFilter.frequency.setValueAtTime(2600, now());
  bodyFilter.Q.setValueAtTime(0.9, now());
  delay.delayTime.setValueAtTime(0.31, now());
  feedback.gain.setValueAtTime(0.2, now());
  delayTone.type = 'lowpass';
  delayTone.frequency.setValueAtTime(3300, now());
  delayGain.gain.setValueAtTime(0.12, now());
  reverbGain.gain.setValueAtTime(0.24, now());
  compressor.threshold.setValueAtTime(-20, now());
  compressor.knee.setValueAtTime(18, now());
  compressor.ratio.setValueAtTime(3, now());
  compressor.attack.setValueAtTime(0.006, now());
  compressor.release.setValueAtTime(0.22, now());
