    const length = Math.floor(audio.sampleRate * 0.055);
    const buffer = audio.createBuffer(1, length, audio.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < length; i += 1) {
      const fade = Math.pow(1 - i / length, 4.8);
      data[i] = (Math.random() * 2 - 1) * fade;
    }
    return buffer;
  };

  convolver.buffer = makeImpulse();
  const pluckBuffer = makePluck();

  dry.connect(bodyFilter);
  bodyFilter.connect(master);
  bodyFilter.connect(delay);
  bodyFilter.connect(convolver);
  delay.connect(delayTone);
  delayTone.connect(feedback);
  feedback.connect(delay);
  delayTone.connect(delayGain);
  delayGain.connect(master);
  convolver.connect(reverbGain);
  reverbGain.connect(master);
  master.connect(compressor);
  compressor.connect(analyser);
  analyser.connect(ctx.audioOut);

  const activeNodes = new Set();
  const timers = new Set();
  let applyingRemote = false;
  let currentStep = -1;
  let pulse = 0;
  let phase = 0;

  const chordOffsets = [
    [0, 4, 7, 11, 14],
    [9, 12, 16, 19, 24],
    [5, 9, 12, 16, 21],
    [7, 11, 14, 19, 23]
  ];
  const arpOrder = [0, 2, 4, 1, 3, 2, 4, 0];

