  const cleanupLater = (time, ...nodes) => {
    const timer = setTimeout(() => {
      timers.delete(timer);
      nodes.forEach((node) => {
        try { node.disconnect(); } catch (error) {}
        activeNodes.delete(node);
      });
    }, Math.max(120, (time - now()) * 1000 + 160));
    timers.add(timer);
  };

  const setParam = (param, value, time = now(), smoothing = 0.04) => {
    param.cancelScheduledValues(time);
    param.setTargetAtTime(value, time, smoothing);
  };

  const updateFx = () => {
    const t = now();
    setParam(master.gain, state.enabled ? state.gain : 0, t, 0.018);
    setParam(bodyFilter.frequency, 900 + state.bright * 5600, t, 0.05);
    setParam(bodyFilter.Q, 0.65 + state.body * 1.9, t, 0.06);
    setParam(feedback.gain, 0.08 + state.room * 0.25, t, 0.06);
    setParam(delayGain.gain, 0.04 + state.motion * 0.16, t, 0.06);
    setParam(delayTone.frequency, 1400 + state.bright * 5200, t, 0.06);
    setParam(reverbGain.gain, 0.1 + state.room * 0.34, t, 0.06);
  };

  const playString = (midi, velocity, time, length, panValue = 0) => {
    if (!state.enabled) return;
    const t = Math.max(time, now() + 0.003);
    const freq = midiToFreq(midi);
    const stopAt = t + length + 0.6;

    const pluck = audio.createBufferSource();
    const pluckGain = audio.createGain();
    const pluckFilter = audio.createBiquadFilter();
    const oscA = audio.createOscillator();
    const oscB = audio.createOscillator();
    const oscGainA = audio.createGain();
    const oscGainB = audio.createGain();
    const voice = audio.createGain();
    const stringFilter = audio.createBiquadFilter();
    const notch = audio.createBiquadFilter();
    const pan = typeof audio.createStereoPanner === 'function' ? audio.createStereoPanner() : null;

    pluck.buffer = pluckBuffer;
    pluckFilter.type = 'bandpass';
    pluckFilter.frequency.setValueAtTime(650 + state.bright * 4200 + velocity * 1200, t);
    pluckFilter.Q.setValueAtTime(1.5 + state.bright * 2.2, t);
    pluckGain.gain.setValueAtTime(0.0001, t);
    pluckGain.gain.exponentialRampToValueAtTime((0.06 + state.bright * 0.06) * velocity, t + 0.004);
    pluckGain.gain.exponentialRampToValueAtTime(0.0001, t + 0.075);

    oscA.type = 'triangle';
    oscB.type = 'sine';
    oscA.frequency.setValueAtTime(freq, t);
    oscB.frequency.setValueAtTime(freq * 2.006, t);
    oscA.detune.setValueAtTime(-2 - state.shimmer * 2.5, t);
    oscB.detune.setValueAtTime(2 + state.shimmer * 3.5, t);

    oscGainA.gain.setValueAtTime(0.0001, t);
    oscGainA.gain.exponentialRampToValueAtTime(0.16 * velocity, t + 0.012);
    oscGainA.gain.exponentialRampToValueAtTime(0.075 * velocity, t + 0.17);
    oscGainA.gain.setTargetAtTime(0.0001, t + length, 0.17 + state.body * 0.2);
    oscGainB.gain.setValueAtTime(0.0001, t);
    oscGainB.gain.exponentialRampToValueAtTime((0.034 + state.shimmer * 0.048) * velocity, t + 0.02);
    oscGainB.gain.setTargetAtTime(0.0001, t + length * 0.7, 0.13);

    stringFilter.type = 'lowpass';
    stringFilter.frequency.setValueAtTime(1300 + state.bright * 4800 + velocity * 900, t);
    stringFilter.frequency.exponentialRampToValueAtTime(720 + state.bright * 2500, t + length);
    stringFilter.Q.setValueAtTime(0.8 + state.body * 2.2, t);
    notch.type = 'notch';
    notch.frequency.setValueAtTime(260 + state.body * 320, t);
    notch.Q.setValueAtTime(0.8, t);
    voice.gain.setValueAtTime(0.88, t);
    if (pan) pan.pan.setValueAtTime(panValue, t);

    pluck.connect(pluckFilter);
    pluckFilter.connect(pluckGain);
    pluckGain.connect(voice);
    oscA.connect(oscGainA);
    oscB.connect(oscGainB);
    oscGainA.connect(voice);
    oscGainB.connect(voice);
    voice.connect(stringFilter);
    stringFilter.connect(notch);
    if (pan) {
      notch.connect(pan);
      pan.connect(dry);
    } else {
      notch.connect(dry);
    }

    pluck.start(t);
    pluck.stop(t + 0.06);
    oscA.start(t);
    oscB.start(t);
    oscA.stop(stopAt);
    oscB.stop(stopAt);

    pulse = Math.max(pulse, velocity);
    remember(pluck, pluckGain, pluckFilter, oscA, oscB, oscGainA, oscGainB, voice, stringFilter, notch, ...(pan ? [pan] : []));
    cleanupLater(stopAt, pluck, pluckGain, pluckFilter, oscA, oscB, oscGainA, oscGainB, voice, stringFilter, notch, ...(pan ? [pan] : []));
  };

  const playChord = (time, duration, step) => {
    const chord = chordOffsets[Math.floor((step % 16) / 4)];
    const base = rootMidi();
    chord.forEach((offset, index) => {
      const octaveDrop = index === 0 ? -12 : 0;
      const delayTime = index * (0.024 + state.motion * 0.018);
      playString(base + offset + octaveDrop, 0.54 + index * 0.04, time + delayTime, duration * (4.2 + state.body * 4), -0.34 + index * 0.17);
    });
  };

  const playArp = (time, duration, step) => {
    if (state.motion < 0.05) return;
    const chord = chordOffsets[Math.floor((step % 16) / 4)];
    const index = arpOrder[step % arpOrder.length] % chord.length;
    const octave = step % 8 >= 4 ? 12 : 0;
    playString(rootMidi() + chord[index] + octave, 0.24 + state.motion * 0.32, time + duration * 0.06, duration * (1.2 + state.body * 1.8), -0.24 + index * 0.12);
  };

  ctx.domRoot.innerHTML = `
    <style>
