      .guitar {
        box-sizing: border-box;
        width: 100%;
        height: 100%;
        min-width: 300px;
        min-height: 230px;
        display: grid;
        grid-template-rows: auto 72px auto 1fr;
        gap: 9px;
        padding: 10px;
        overflow: hidden;
        color: #f8fafc;
        background:
