        gap: 7px;
      }
      h2 {
        margin: 0;
        color: #fde68a;
        font-size: 14px;
        line-height: 1;
        letter-spacing: 0;
      }
      .tag {
        margin-top: 2px;
        color: #94a3b8;
        font-size: 9px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
      }
      button, input, select { font: inherit; }
      .toggle {
        height: 28px;
        min-width: 48px;
        padding: 0 9px;
        border: 1px solid rgba(252, 211, 77, 0.72);
        border-radius: 5px;
        color: #1c1917;
        background: #fde68a;
        cursor: pointer;
      }
      .toggle.off {
        color: #cbd5e1;
        background: rgba(15, 23, 42, 0.82);
      }
      select {
        height: 28px;
        color: #ecfeff;
        background: rgba(2, 6, 23, 0.78);
        border: 1px solid rgba(148, 163, 184, 0.34);
        border-radius: 5px;
        outline: none;
      }
      .scope {
        min-width: 0;
        border: 1px solid rgba(148, 163, 184, 0.28);
        border-radius: 6px;
        background: #040609;
        overflow: hidden;
      }
      canvas {
        display: block;
        width: 100%;
        height: 100%;
      }
      .controls {
        display: grid;
        grid-template-columns: repeat(3, minmax(0, 1fr));
