      .string {
        height: 2px;
        border-radius: 999px;
        background: linear-gradient(90deg, rgba(148, 163, 184, 0.2), rgba(253, 230, 138, 0.88), rgba(148, 163, 184, 0.2));
        box-shadow: 0 0 8px rgba(252, 211, 77, 0.22);
      }
