        background: linear-gradient(90deg, rgba(45, 212, 191, 0.2), #fef3c7, rgba(45, 212, 191, 0.2));
        box-shadow: 0 0 14px rgba(252, 211, 77, 0.65);
      }
    </style>
    <div class="guitar">
      <div class="top">
        <div>
          <h2>Beautiful Guitar</h2>
          <div class="tag">warm plucks / soft chords / room</div>
        </div>
        <select id="key" title="key"></select>
        <button class="toggle" id="enabled" type="button"></button>
      </div>
      <div class="scope"><canvas id="scope" width="340" height="72"></canvas></div>
      <div class="controls">
        <label>gain <input id="gain" type="range" min="0" max="1" step="0.01"></label>
        <label>body <input id="body" type="range" min="0" max="1" step="0.01"></label>
        <label>bright <input id="bright" type="range" min="0" max="1" step="0.01"></label>
        <label>room <input id="room" type="range" min="0" max="1" step="0.01"></label>
        <label>motion <input id="motion" type="range" min="0" max="1" step="0.01"></label>
